public void countingSort(int[] arr) {
    int n = arr.length;
    if (n <= 1) return;

    // Find the maximum element
    int max = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] > max) {
            max = arr[i];
        }
    }

    // Create count array
    int[] count = new int[max + 1];

    // Count occurrences
    for (int i = 0; i < n; i++) {
        count[arr[i]]++;
    }

    // Modify count array to store actual positions
    for (int i = 1; i <= max; i++) {
        count[i] += count[i - 1];
    }

    // Create output array
    int[] output = new int[n];

    // Build output array
    for (int i = n - 1; i >= 0; i--) {
        output[count[arr[i]] - 1] = arr[i];
        count[arr[i]]--;
    }

    // Copy output array back to original array
    for (int i = 0; i < n; i++) {
        arr[i] = output[i];
    }
}

