from typing import List

def counting_sort(arr: List[int]) -> None:
    n = len(arr)
    if n <= 1:
        return

    max_val = max(arr)
    count = [0] * (max_val + 1)

    for val in arr:
        count[val] += 1

    for i in range(1, max_val + 1):
        count[i] += count[i - 1]

    output = [0] * n
    for i in range(n - 1, -1, -1):
        output[count[arr[i]] - 1] = arr[i]
        count[arr[i]] -= 1

    for i in range(n):
        arr[i] = output[i]

